"use client";

import { useEffect, useState } from "react";
import { VoiceInput } from "@/components/VoiceInput";
import { ManualEntry } from "@/components/ManualEntry";
import { ReceiptScanner } from "@/components/ReceiptScanner";
import { Dashboard } from "@/components/Dashboard";
import { Insights } from "@/components/Insights";
import { addExpense, getExpenses, deleteExpense, Expense, loginWithGoogle, logout, auth } from "@/lib/firebase";
import { onAuthStateChanged, User } from "firebase/auth";
import { LogOut } from "lucide-react";

export default function Home() {
  const [user, setUser] = useState<User | null>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isProcessingVoice, setIsProcessingVoice] = useState(false);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      setIsAuthChecking(false);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const fetchInitialLogs = async () => {
      if (!user) return;
      setIsLoading(true);
      try {
        const data = await getExpenses(user.uid);
        setExpenses(data);
      } catch (error) {
        console.error("Error fetching initial expenses:", error);
      } finally {
        setIsLoading(false);
      }
    };

    if (user) {
      fetchInitialLogs();
    } else {
      setExpenses([]);
    }
  }, [user]);

  const handleAddExpense = async (expenseData: Omit<Expense, "id" | "createdAt" | "userId">) => {
    if (!user) {
      alert("Must be logged in to save expenses");
      return;
    }
    try {
      const savedExpense = await addExpense({ ...expenseData, userId: user.uid });
      setExpenses(prev => [savedExpense as Expense, ...prev]);
    } catch (error: any) {
      console.error("Error saving expense:", error);
      alert("Error saving expense: " + error.message);
    }
  };

  const handleTranscript = async (transcript: string) => {
    setIsProcessingVoice(true);
    try {
      // 1. Send text to our AI Parse API
      const res = await fetch("/api/parse-expense", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ transcript }),
      });

      if (!res.ok) {
        const errData = await res.json().catch(() => ({}));
        throw new Error(errData.error || "Failed connecting to AI API");
      }
      
      const parsedData = await res.json();
      
      // 2. Validate parsed data & Structure for DB
      if (parsedData && parsedData.amount) {
         await handleAddExpense({
           amount: Number(parsedData.amount),
           category: parsedData.category || "Uncategorized",
           vendor: parsedData.vendor || "Unknown",
           date: parsedData.date || new Date().toISOString().split('T')[0],
           rawText: transcript
         });
      } else {
        alert("Couldn't understand the expense completely. Please try again.");
      }

    } catch (error: any) {
      console.error("Pipeline error:", error);
      alert("Error: " + (error.message || "An error occurred while processing your expense."));
    } finally {
      setIsProcessingVoice(false);
    }
  };

  const handleDeleteExpense = async (id: string) => {
    if (!confirm("Are you sure you want to delete this expense?")) return;
    try {
      await deleteExpense(id);
      setExpenses(prev => prev.filter(e => e.id !== id));
    } catch (e) {
      console.error("Error deleting", e);
      alert("Failed to delete expense");
    }
  };

  if (isAuthChecking) {
    return <main className="min-h-screen flex items-center justify-center">Loading...</main>;
  }

  if (!user) {
    return (
      <main className="min-h-screen relative p-6 sm:p-12 flex flex-col items-center justify-center overflow-hidden">
        <div className="absolute top-0 left-0 w-[500px] h-[500px] bg-primary-600/20 rounded-full blur-[100px] -translate-x-1/2 -translate-y-1/2" />
        <div className="absolute top-1/2 right-0 w-[400px] h-[400px] bg-blue-500/20 rounded-full blur-[100px] translate-x-1/3" />
        
        <div className="glass dark:glass-dark rounded-3xl p-12 text-center shadow-2xl relative z-10 max-w-md w-full border border-white/10 animate-in zoom-in-95 duration-700">
          <div className="w-20 h-20 bg-gradient-to-br from-primary-500 to-blue-500 rounded-2xl mx-auto flex items-center justify-center shadow-lg shadow-primary-500/30 mb-8 border border-white/20">
             <span className="text-4xl">🎙️</span>
          </div>
          <h1 className="text-3xl font-bold tracking-tight mb-3">AI Expense Tracker</h1>
          <p className="text-foreground/60 mb-8 leading-relaxed">Login to securely log, sync, and analyze your finances across all devices.</p>
          <button 
            onClick={loginWithGoogle}
            className="w-full py-4 px-6 rounded-2xl bg-white text-black font-bold text-lg hover:bg-gray-100 transition-all flex items-center justify-center gap-3 shadow-xl"
          >
            <svg width="24" height="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
              <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
              <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
              <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
              <path d="M1 1h22v22H1z" fill="none"/>
            </svg>
            Sign in with Google
          </button>
        </div>
      </main>
    );
  }

  return (
    <main className="min-h-screen relative p-6 sm:p-12 overflow-x-hidden selection:bg-primary-500/30">
      {/* Decorative blobs for modern UI */}
      <div className="absolute top-0 left-0 w-[500px] h-[500px] bg-primary-600/20 rounded-full blur-[100px] -translate-x-1/2 -translate-y-1/2" />
      <div className="absolute top-1/2 right-0 w-[400px] h-[400px] bg-blue-500/20 rounded-full blur-[100px] translate-x-1/3" />
      
      <div className="max-w-5xl mx-auto space-y-10 relative z-10">
        
        <div className="flex justify-end pt-4">
           <button 
             onClick={logout} 
             className="flex items-center gap-2 text-sm text-foreground/50 hover:text-red-400 bg-white/5 px-4 py-2 rounded-full transition-colors"
           >
             <LogOut className="w-4 h-4" /> Sign Out
           </button>
        </div>
        
        <header className="text-center space-y-4 pb-6 animate-in fade-in slide-in-from-top-6 duration-700">
          <h1 className="text-4xl md:text-5xl font-extrabold tracking-tight bg-gradient-to-br from-foreground to-foreground/70 bg-clip-text text-transparent">
            AI Expense Tracker
          </h1>
          <p className="text-foreground/60 max-w-xl mx-auto">
            Just say what you spent. We'll extract the details, log the date, and analyze your finances.
          </p>
        </header>
        
        <section className="animate-in zoom-in-95 duration-500 delay-100 max-w-2xl mx-auto relative z-20">
          <VoiceInput onTranscriptComplete={handleTranscript} isProcessing={isProcessingVoice} />
          <div className="grid grid-cols-2 gap-4 mt-4">
            <ReceiptScanner onAddExpense={handleAddExpense} />
            <ManualEntry onAddExpense={handleAddExpense} />
          </div>
        </section>

        <section className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-6">
            <h2 className="text-2xl font-bold mb-4 px-2">Your Dashboard</h2>
            {isLoading ? (
              <div className="glass dark:glass-dark rounded-3xl p-12 text-center animate-pulse-slow">
                Loading your data...
              </div>
            ) : (
              <Dashboard expenses={expenses} onDelete={handleDeleteExpense} />
            )}
          </div>
          <div className="space-y-6">
             <h2 className="text-2xl font-bold mb-4 px-2">Insights</h2>
             <Insights expenses={expenses} />
          </div>
        </section>

      </div>
    </main>
  );
}
